<template><div class="flex gap-2"><select class="input" v-model="local.status_id" @change="emitChange"><option value="">Status</option><option v-for="s in filters.statuses" :key="s.id" :value="s.id">{{ s.name }}</option></select><select class="input" v-model="local.type_id" @change="emitChange"><option value="">Type</option><option v-for="t in filters.types" :key="t.id" :value="t.id">{{ t.name }}</option></select></div></template>
<script setup>import {reactive,watch} from 'vue'; const props=defineProps({filters:Object,query:Object}); const emit=defineEmits(['update:query','change']); const local=reactive({status_id:props.query.status_id,type_id:props.query.type_id}); watch(()=>props.query,v=>Object.assign(local,v)); const emitChange=()=>{emit('update:query',{...props.query,...local}); emit('change');};</script>
